function updateContent(lang) {
    document.querySelectorAll('[data-lang-key]').forEach((element)=>{
        const key = element.getAttribute('data-lang-key');
        if (![
            'option1Text',
            'option2Text',
            'languageOptionText'
        ].includes(key)) {
            if (translations[lang] && translations[lang][key]) {
                if (element.tagName === 'TITLE') element.textContent = translations[lang][key];
                else element.innerHTML = translations[lang][key];
            }
        }
    });
    const namePlaceholder = document.querySelector('[data-lang-key="yourNamePlaceholder"]');
    if (namePlaceholder) namePlaceholder.setAttribute('placeholder', translations[lang].yourNamePlaceholder);
    const reviewPlaceholder = document.querySelector('[data-lang-key="yourReviewPlaceholder"]');
    if (reviewPlaceholder) reviewPlaceholder.setAttribute('placeholder', translations[lang].yourReviewPlaceholder);
    document.documentElement.lang = lang;
    const booksCodePlaceholder = document.querySelector('[data-lang-key="codeBooks"][type="password"]');
    if (booksCodePlaceholder) booksCodePlaceholder.setAttribute('placeholder', translations[lang].codeBooks);
    document.documentElement.lang = lang;
}
let currentLang = localStorage.getItem('lang') || 'uk';
translations.uk.option1Text = "\u0423\u043A\u0440\u0430\u0457\u043D\u0441\u044C\u043A\u0430";
translations.uk.option2Text = "\u0410\u043D\u0433\u043B\u0456\u0439\u0441\u044C\u043A\u0430";
translations.en.option1Text = "Ukrainian";
translations.en.option2Text = "English";
document.addEventListener('DOMContentLoaded', ()=>{
    updateContent(currentLang);
    const ukrainianRadio = document.getElementById('option-1');
    const englishRadio = document.getElementById('option-2');
    if (currentLang === 'uk') {
        if (ukrainianRadio) ukrainianRadio.checked = true;
    } else if (englishRadio) englishRadio.checked = true;
    if (ukrainianRadio) ukrainianRadio.addEventListener('change', ()=>{
        currentLang = 'uk';
        localStorage.setItem('lang', 'uk');
        updateContent('uk');
    });
    if (englishRadio) englishRadio.addEventListener('change', ()=>{
        currentLang = 'en';
        localStorage.setItem('lang', 'en');
        updateContent('en');
    });
});

